}

u32 GetTexExponent(int dimension)
{
    u32 exp;

    if (dimension <= 1)
        return 0;

    exp = 1;
    while (exp < 11 && (1 << exp) < dimension)
        exp++;

    if (exp >= 11)
        return 0;
    return exp;
}

int gsAllocBuffer(u32 psm, int *params)
{
    int start_page = g_gs_vram_ptr;
    int bpp;
    int total_bytes;
    int pages;

    bpp = psmToBppGS(psm);
    g_gs_current_psm = psm;

    total_bytes = ((params[2] + 63) & ~63) * params[3] * bpp;
    pages = (total_bytes + 31) / 32;
    pages = (pages + 63) / 64;
    g_gs_vram_ptr += pages;

    return start_page;
}

void gsInitAlloc(void)
{
    int n;

    g_gs_current_psm = (u32)-1;
    n = screenW * screenH;
    g_gs_vram_ptr = (n / 64) * 3;
}

void gsAllocExtraBuffers(void)
{
    int params[4];

    params[0] = 0;
    params[1] = 0;
    params[2] = screenW;
    params[3] = screenH;
    gsExtraBuffers[0] = gsAllocBuffer(0, params);
    gsExtraBuffers[1] = gsAllocBuffer(0, params);
}

